module top_module(
               input            CLK,
               input            RST, 
               input            UP,
               input            DOWN,
               output reg [3:0] CODE
               );reg [3:0]                    ctr_4;
   always @( posedge CLK ) begin
      if ( !RST )
        ctr_4 <= 4'b0000;
      else if ( UP ) 
        ctr_4 <= ctr_4 + 4'b0001;
      else if ( DOWN ) 
        ctr_4 <= ctr_4 - 4'b0001;
   end


   always @* begin
      CODE = ctr_4 ^ (ctr_4 >> 1);
   end

endmodule
